const config = {
  "previewFeatures": [],
  "clientVersion": "7.7.0",
  "engineVersion": "75cbdc1eb7150937890ad5465d861175c6624711",
  "activeProvider": "postgresql",
  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/client\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ─── ENUMS ───────────────────────────────────────────────────────────────────\n\nenum UserRole {\n  SUPER_ADMIN\n  ADMIN\n  MANAGER\n  AGENT\n}\n\nenum ConversationStatus {\n  OPEN\n  AI_HANDLING\n  WAITING_HUMAN\n  HUMAN_HANDLING\n  RESOLVED\n  CLOSED\n  SPAM\n}\n\nenum MessageDirection {\n  INBOUND\n  OUTBOUND\n}\n\nenum MessageStatus {\n  PENDING\n  SENT\n  DELIVERED\n  READ\n  FAILED\n}\n\nenum MessageType {\n  TEXT\n  IMAGE\n  VIDEO\n  AUDIO\n  DOCUMENT\n  STICKER\n  LOCATION\n  CONTACT\n  TEMPLATE\n  INTERACTIVE\n}\n\nenum LeadStatus {\n  NEW\n  CONTACTED\n  QUALIFIED\n  PROPOSAL_SENT\n  NEGOTIATING\n  WON\n  LOST\n  DISQUALIFIED\n}\n\nenum DealStage {\n  LEAD_IN\n  QUALIFIED\n  PROPOSAL\n  NEGOTIATION\n  WON\n  LOST\n}\n\nenum TaskStatus {\n  TODO\n  IN_PROGRESS\n  DONE\n  CANCELLED\n}\n\nenum TaskPriority {\n  LOW\n  MEDIUM\n  HIGH\n  URGENT\n}\n\nenum PaymentStatus {\n  PENDING\n  PAID\n  FAILED\n  REFUNDED\n  EXPIRED\n}\n\nenum AiProvider {\n  GEMINI\n  OPENAI\n  ANTHROPIC\n  GROQ\n  DEEPSEEK\n  XAI\n  MISTRAL\n  TOGETHER\n  MOONSHOT\n  OLLAMA\n  OPENROUTER\n  CUSTOM\n}\n\nenum PaymentProvider {\n  RAZORPAY\n  STRIPE\n  CASHFREE\n  PHONEPE\n  PAYU\n  NONE\n}\n\nenum WaAccountStatus {\n  DISCONNECTED\n  QR_PENDING\n  CONNECTING\n  CONNECTED\n  BANNED\n  ERROR\n}\n\nenum AuditAction {\n  CREATE\n  UPDATE\n  DELETE\n  AI_TOOL_CALL\n  AI_REPLY\n  PAYMENT_CREATED\n  PAYMENT_RECEIVED\n  WA_SESSION_START\n  WA_SESSION_END\n  USER_LOGIN\n  USER_LOGOUT\n  SETTINGS_CHANGE\n}\n\n// ─── COMPANY ──────────────────────────────────────────────────────────────────\n\nmodel Company {\n  id        String   @id @default(cuid())\n  name      String\n  slug      String   @unique\n  email     String?\n  phone     String?\n  website   String?\n  logoUrl   String?\n  timezone  String   @default(\"UTC\")\n  isActive  Boolean  @default(true)\n  setupDone Boolean  @default(false)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  users            User[]\n  whatsappAccounts WhatsAppAccount[]\n  contacts         Contact[]\n  conversations    Conversation[]\n  leads            Lead[]\n  deals            Deal[]\n  tasks            Task[]\n  payments         Payment[]\n  broadcasts       Broadcast[]\n  auditLogs        AuditLog[]\n  aiConfig         AiConfig?\n  paymentConfig    PaymentConfig?\n  webhookEndpoints WebhookEndpoint[]\n\n  @@index([slug])\n  @@index([isActive])\n}\n\n// ─── USER ─────────────────────────────────────────────────────────────────────\n\nmodel User {\n  id               String    @id @default(cuid())\n  companyId        String\n  email            String\n  passwordHash     String\n  firstName        String\n  lastName         String\n  avatarUrl        String?\n  role             UserRole  @default(AGENT)\n  isActive         Boolean   @default(true)\n  refreshTokenHash String?\n  lastLoginAt      DateTime?\n  createdAt        DateTime  @default(now())\n  updatedAt        DateTime  @updatedAt\n\n  company       Company        @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  assignedConvs Conversation[] @relation(\"AssignedAgent\")\n  assignedLeads Lead[]         @relation(\"AssignedAgent\")\n  assignedDeals Deal[]         @relation(\"AssignedAgent\")\n  assignedTasks Task[]         @relation(\"AssignedAgent\")\n  createdTasks  Task[]         @relation(\"CreatedBy\")\n  auditLogs     AuditLog[]\n\n  @@unique([companyId, email])\n  @@index([companyId])\n  @@index([email])\n}\n\n// ─── WHATSAPP ACCOUNT ─────────────────────────────────────────────────────────\n\nmodel WhatsAppAccount {\n  id                String          @id @default(cuid())\n  companyId         String\n  phoneNumber       String\n  displayName       String?\n  status            WaAccountStatus @default(DISCONNECTED)\n  provider          String          @default(\"baileys\")\n  accessTokenEnc    String?\n  phoneNumberId     String?\n  sessionDataEnc    Bytes?\n  qrCode            String?\n  warmupStage       Int             @default(0)\n  warmupStartedAt   DateTime?\n  dailyMessageLimit Int             @default(50)\n  messagesSentToday Int             @default(0)\n  lastResetAt       DateTime?\n  consecutiveErrors Int             @default(0)\n  lastErrorAt       DateTime?\n  lastConnectedAt   DateTime?\n  createdAt         DateTime        @default(now())\n  updatedAt         DateTime        @updatedAt\n\n  company       Company        @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  conversations Conversation[]\n  messages      Message[]\n\n  @@unique([companyId, phoneNumber])\n  @@index([companyId])\n  @@index([status])\n}\n\n// ─── CONTACT ──────────────────────────────────────────────────────────────────\n\nmodel Contact {\n  id             String    @id @default(cuid())\n  companyId      String\n  phoneNumber    String\n  displayName    String?\n  firstName      String?\n  lastName       String?\n  email          String?\n  avatarUrl      String?\n  tags           String[]\n  customFields   Json      @default(\"{}\")\n  notes          String?\n  lifecycleStage String    @default(\"SUBSCRIBER\")\n  score          Int       @default(0)\n  companyName    String?\n  jobTitle       String?\n  address        String?\n  socialLinks    Json      @default(\"{}\")\n  referredById   String?\n  isBlocked      Boolean   @default(false)\n  optedOut       Boolean   @default(false)\n  optedOutAt     DateTime?\n  lastSeenAt     DateTime?\n  createdAt      DateTime  @default(now())\n  updatedAt      DateTime  @updatedAt\n  deletedAt      DateTime?\n\n  company       Company        @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  referredBy    Contact?       @relation(\"ContactReferrals\", fields: [referredById], references: [id])\n  referrals     Contact[]      @relation(\"ContactReferrals\")\n  conversations Conversation[]\n  leads         Lead[]\n  deals         Deal[]\n  tasks         Task[]\n  payments      Payment[]\n  contactNotes  ContactNote[]\n\n  @@unique([companyId, phoneNumber])\n  @@index([companyId])\n  @@index([phoneNumber])\n  @@index([companyId, deletedAt])\n  @@index([tags])\n  @@index([companyId, lifecycleStage])\n  @@index([companyId, score])\n}\n\n// ─── CONVERSATION ─────────────────────────────────────────────────────────────\n\nmodel Conversation {\n  id                String             @id @default(cuid())\n  companyId         String\n  contactId         String\n  whatsappAccountId String\n  assignedAgentId   String?\n  status            ConversationStatus @default(OPEN)\n  aiEnabled         Boolean            @default(true)\n  unreadCount       Int                @default(0)\n  lastMessageAt     DateTime?\n  lastMessageText   String?\n  resolvedAt        DateTime?\n  metadata          Json               @default(\"{}\")\n  createdAt         DateTime           @default(now())\n  updatedAt         DateTime           @updatedAt\n\n  company         Company         @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  contact         Contact         @relation(fields: [contactId], references: [id])\n  whatsappAccount WhatsAppAccount @relation(fields: [whatsappAccountId], references: [id])\n  assignedAgent   User?           @relation(\"AssignedAgent\", fields: [assignedAgentId], references: [id])\n  messages        Message[]\n  aiContextCache  AiContextCache?\n\n  @@index([companyId])\n  @@index([contactId])\n  @@index([status])\n  @@index([companyId, status])\n  @@index([lastMessageAt])\n}\n\n// ─── MESSAGE ──────────────────────────────────────────────────────────────────\n\nmodel Message {\n  id                String           @id @default(cuid())\n  companyId         String\n  conversationId    String\n  whatsappAccountId String\n  whatsappMessageId String?\n  idempotencyKey    String?          @unique\n  direction         MessageDirection\n  type              MessageType      @default(TEXT)\n  status            MessageStatus    @default(PENDING)\n  body              String?\n  mediaUrl          String?\n  mediaType         String?\n  mediaSizeBytes    Int?\n  mediaCaption      String?\n  latitude          Float?\n  longitude         Float?\n  replyToMessageId  String?\n  isAiGenerated     Boolean          @default(false)\n  aiProvider        String?\n  aiModel           String?\n  aiTokensUsed      Int?\n  aiLatencyMs       Int?\n  errorMessage      String?\n  sentAt            DateTime?\n  deliveredAt       DateTime?\n  readAt            DateTime?\n  failedAt          DateTime?\n  createdAt         DateTime         @default(now())\n\n  conversation    Conversation    @relation(fields: [conversationId], references: [id], onDelete: Cascade)\n  whatsappAccount WhatsAppAccount @relation(fields: [whatsappAccountId], references: [id])\n  replyTo         Message?        @relation(\"ReplyThread\", fields: [replyToMessageId], references: [id])\n  replies         Message[]       @relation(\"ReplyThread\")\n\n  @@index([conversationId])\n  @@index([whatsappMessageId])\n  @@index([idempotencyKey])\n  @@index([companyId, createdAt])\n  @@index([direction, status])\n}\n\n// ─── LEAD ─────────────────────────────────────────────────────────────────────\n\nmodel Lead {\n  id              String     @id @default(cuid())\n  companyId       String\n  contactId       String\n  assignedAgentId String?\n  title           String\n  status          LeadStatus @default(NEW)\n  source          String?\n  score           Int        @default(0)\n  estimatedValue  Float?\n  currency        String     @default(\"INR\")\n  notes           String?\n  customFields    Json       @default(\"{}\")\n  lostReason      String?\n  wonAt           DateTime?\n  lostAt          DateTime?\n  createdAt       DateTime   @default(now())\n  updatedAt       DateTime   @updatedAt\n  deletedAt       DateTime?\n\n  company       Company @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  contact       Contact @relation(fields: [contactId], references: [id])\n  assignedAgent User?   @relation(\"AssignedAgent\", fields: [assignedAgentId], references: [id])\n  deals         Deal[]\n\n  @@index([companyId])\n  @@index([contactId])\n  @@index([status])\n  @@index([companyId, status])\n}\n\n// ─── DEAL ─────────────────────────────────────────────────────────────────────\n\nmodel Deal {\n  id              String    @id @default(cuid())\n  companyId       String\n  contactId       String\n  leadId          String?\n  assignedAgentId String?\n  title           String\n  stage           DealStage @default(LEAD_IN)\n  value           Float\n  currency        String    @default(\"INR\")\n  probability     Int       @default(20)\n  expectedCloseAt DateTime?\n  wonAt           DateTime?\n  lostAt          DateTime?\n  lostReason      String?\n  notes           String?\n  customFields    Json      @default(\"{}\")\n  createdAt       DateTime  @default(now())\n  updatedAt       DateTime  @updatedAt\n  deletedAt       DateTime?\n\n  company       Company   @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  contact       Contact   @relation(fields: [contactId], references: [id])\n  lead          Lead?     @relation(fields: [leadId], references: [id])\n  assignedAgent User?     @relation(\"AssignedAgent\", fields: [assignedAgentId], references: [id])\n  payments      Payment[]\n  tasks         Task[]\n\n  @@index([companyId])\n  @@index([contactId])\n  @@index([stage])\n  @@index([companyId, stage])\n}\n\n// ─── TASK ─────────────────────────────────────────────────────────────────────\n\nmodel Task {\n  id              String       @id @default(cuid())\n  companyId       String\n  contactId       String?\n  dealId          String?\n  assignedAgentId String?\n  createdById     String?\n  title           String\n  description     String?\n  status          TaskStatus   @default(TODO)\n  priority        TaskPriority @default(MEDIUM)\n  dueAt           DateTime?\n  completedAt     DateTime?\n  reminderSentAt  DateTime?\n  createdAt       DateTime     @default(now())\n  updatedAt       DateTime     @updatedAt\n\n  company       Company  @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  contact       Contact? @relation(fields: [contactId], references: [id])\n  deal          Deal?    @relation(fields: [dealId], references: [id])\n  assignedAgent User?    @relation(\"AssignedAgent\", fields: [assignedAgentId], references: [id])\n  createdBy     User?    @relation(\"CreatedBy\", fields: [createdById], references: [id])\n\n  @@index([companyId])\n  @@index([assignedAgentId])\n  @@index([dueAt])\n  @@index([status])\n}\n\n// ─── AI CONFIG ────────────────────────────────────────────────────────────────\n\nmodel AiConfig {\n  id                 String     @id @default(cuid())\n  companyId          String     @unique\n  provider           AiProvider @default(GEMINI)\n  model              String     @default(\"gemini-2.0-flash\")\n  apiKeyEncrypted    String?\n  baseUrl            String?\n  systemPrompt       String     @default(\"You are a helpful sales assistant. Help the customer and capture their information.\")\n  tone               String     @default(\"professional\")\n  maxTokens          Int        @default(1024)\n  temperature        Float      @default(0.7)\n  autoReplyEnabled   Boolean    @default(true)\n  toolCallingEnabled Boolean    @default(true)\n  testStatus         String?\n  testError          String?\n  updatedAt          DateTime   @updatedAt\n\n  company Company @relation(fields: [companyId], references: [id], onDelete: Cascade)\n}\n\nmodel AiContextCache {\n  id             String   @id @default(cuid())\n  conversationId String   @unique\n  messages       Json\n  tokenCount     Int\n  pruneCount     Int      @default(0)\n  updatedAt      DateTime @updatedAt\n\n  conversation Conversation @relation(fields: [conversationId], references: [id], onDelete: Cascade)\n\n  @@index([conversationId])\n}\n\n// ─── PAYMENT ──────────────────────────────────────────────────────────────────\n\nmodel PaymentConfig {\n  id              String          @id @default(cuid())\n  companyId       String          @unique\n  provider        PaymentProvider @default(NONE)\n  keyEncrypted    String?\n  secretEncrypted String?\n  webhookSecret   String?\n  currency        String          @default(\"INR\")\n  testMode        Boolean         @default(true)\n  updatedAt       DateTime        @updatedAt\n\n  company Company @relation(fields: [companyId], references: [id], onDelete: Cascade)\n}\n\nmodel Payment {\n  id             String          @id @default(cuid())\n  companyId      String\n  contactId      String?\n  dealId         String?\n  provider       PaymentProvider\n  externalId     String?\n  linkUrl        String?\n  amount         Int\n  currency       String          @default(\"INR\")\n  description    String?\n  status         PaymentStatus   @default(PENDING)\n  paidAt         DateTime?\n  refundedAt     DateTime?\n  webhookPayload Json?\n  idempotencyKey String          @unique\n  createdAt      DateTime        @default(now())\n  updatedAt      DateTime        @updatedAt\n\n  company Company  @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  contact Contact? @relation(fields: [contactId], references: [id])\n  deal    Deal?    @relation(fields: [dealId], references: [id])\n\n  @@index([companyId])\n  @@index([externalId])\n  @@index([status])\n  @@index([idempotencyKey])\n}\n\n// ─── BROADCAST ────────────────────────────────────────────────────────────────\n\nmodel Broadcast {\n  id               String    @id @default(cuid())\n  companyId        String\n  name             String\n  message          String\n  mediaUrl         String?\n  targetTags       String[]\n  targetContactIds String[]\n  scheduledAt      DateTime?\n  startedAt        DateTime?\n  completedAt      DateTime?\n  totalCount       Int       @default(0)\n  sentCount        Int       @default(0)\n  failedCount      Int       @default(0)\n  createdAt        DateTime  @default(now())\n\n  company Company @relation(fields: [companyId], references: [id], onDelete: Cascade)\n\n  @@index([companyId])\n  @@index([scheduledAt])\n}\n\n// ─── AUDIT LOG ────────────────────────────────────────────────────────────────\n\nmodel AuditLog {\n  id         String      @id @default(cuid())\n  companyId  String\n  userId     String?\n  action     AuditAction\n  entityType String?\n  entityId   String?\n  oldValue   Json?\n  newValue   Json?\n  ipAddress  String?\n  createdAt  DateTime    @default(now())\n\n  company Company @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  user    User?   @relation(fields: [userId], references: [id])\n\n  @@index([companyId])\n  @@index([action])\n  @@index([entityType, entityId])\n  @@index([createdAt])\n}\n\n// ─── WEBHOOK ENDPOINT ─────────────────────────────────────────────────────────\n\nmodel WebhookEndpoint {\n  id        String   @id @default(cuid())\n  companyId String\n  url       String\n  secret    String\n  events    String[]\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n\n  company Company @relation(fields: [companyId], references: [id], onDelete: Cascade)\n\n  @@index([companyId])\n}\n\n// ─── CONTACT NOTE ────────────────────────────────────────────────────────────\n\nmodel ContactNote {\n  id        String   @id @default(cuid())\n  companyId String\n  contactId String\n  authorId  String?\n  content   String\n  createdAt DateTime @default(now())\n\n  contact Contact @relation(fields: [contactId], references: [id], onDelete: Cascade)\n\n  @@index([contactId])\n  @@index([companyId])\n}\n\n// ─── TAG ─────────────────────────────────────────────────────────────────────\n\nmodel Tag {\n  id          String  @id @default(cuid())\n  companyId   String\n  name        String\n  color       String  @default(\"#8b5cf6\")\n  description String?\n\n  @@unique([companyId, name])\n  @@index([companyId])\n}\n\n// ─── SEGMENT ─────────────────────────────────────────────────────────────────\n\nmodel Segment {\n  id         String   @id @default(cuid())\n  companyId  String\n  name       String\n  type       String   @default(\"DYNAMIC\") // DYNAMIC or STATIC\n  filters    Json     @default(\"{}\") // For DYNAMIC: filter rules\n  contactIds String[] // For STATIC: manually added contacts\n  count      Int      @default(0)\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  @@unique([companyId, name])\n  @@index([companyId])\n}\n\n// ─── CUSTOM FIELD DEFINITION ─────────────────────────────────────────────────\n\nmodel CustomFieldDefinition {\n  id         String   @id @default(cuid())\n  companyId  String\n  entityType String // \"contact\", \"lead\", \"deal\"\n  fieldName  String\n  fieldType  String // \"text\", \"number\", \"date\", \"select\", \"multiselect\"\n  options    String[] // For select/multiselect\n  required   Boolean  @default(false)\n  sortOrder  Int      @default(0)\n  createdAt  DateTime @default(now())\n\n  @@unique([companyId, entityType, fieldName])\n  @@index([companyId, entityType])\n}\n\n// ─── NOTIFICATION ────────────────────────────────────────────────────────────\n\nmodel Notification {\n  id        String   @id @default(cuid())\n  companyId String\n  userId    String?\n  title     String\n  body      String\n  type      String   @default(\"info\") // info, success, warning, error\n  link      String?\n  read      Boolean  @default(false)\n  createdAt DateTime @default(now())\n\n  @@index([companyId, userId, read])\n  @@index([companyId, createdAt])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// PHASE 2: COMMUNICATION\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel Template {\n  id        String   @id @default(cuid())\n  companyId String\n  name      String\n  category  String   @default(\"general\") // greeting, follow-up, payment, support\n  body      String\n  variables String[] // e.g. [\"name\", \"amount\"]\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([companyId, name])\n  @@index([companyId, category])\n}\n\nmodel CannedResponse {\n  id        String @id @default(cuid())\n  companyId String\n  shortcut  String // e.g. \"/hello\"\n  body      String\n\n  @@unique([companyId, shortcut])\n  @@index([companyId])\n}\n\nmodel Sequence {\n  id        String   @id @default(cuid())\n  companyId String\n  name      String\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  steps       SequenceStep[]\n  enrollments SequenceEnrollment[]\n\n  @@unique([companyId, name])\n  @@index([companyId])\n}\n\nmodel SequenceStep {\n  id         String  @id @default(cuid())\n  sequenceId String\n  sortOrder  Int\n  delayHours Int     @default(24)\n  action     String  @default(\"send_message\") // send_message, send_email, wait\n  message    String?\n  templateId String?\n\n  sequence Sequence @relation(fields: [sequenceId], references: [id], onDelete: Cascade)\n\n  @@index([sequenceId])\n}\n\nmodel SequenceEnrollment {\n  id          String    @id @default(cuid())\n  sequenceId  String\n  contactId   String\n  companyId   String\n  currentStep Int       @default(0)\n  status      String    @default(\"ACTIVE\") // ACTIVE, PAUSED, COMPLETED, STOPPED\n  nextRunAt   DateTime?\n  enrolledAt  DateTime  @default(now())\n  completedAt DateTime?\n\n  sequence Sequence @relation(fields: [sequenceId], references: [id], onDelete: Cascade)\n\n  @@index([companyId, status])\n  @@index([sequenceId, status])\n  @@index([nextRunAt])\n}\n\nmodel CallLog {\n  id        String   @id @default(cuid())\n  companyId String\n  contactId String\n  agentId   String?\n  duration  Int? // seconds\n  outcome   String? // connected, no_answer, voicemail, callback\n  notes     String?\n  createdAt DateTime @default(now())\n\n  @@index([companyId, contactId])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// PHASE 3: SALES PIPELINE\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel Pipeline {\n  id        String   @id @default(cuid())\n  companyId String\n  name      String\n  isDefault Boolean  @default(false)\n  createdAt DateTime @default(now())\n\n  stages PipelineStage[]\n\n  @@unique([companyId, name])\n  @@index([companyId])\n}\n\nmodel PipelineStage {\n  id          String @id @default(cuid())\n  pipelineId  String\n  name        String\n  color       String @default(\"#8b5cf6\")\n  sortOrder   Int\n  probability Int    @default(0) // 0-100\n\n  pipeline Pipeline @relation(fields: [pipelineId], references: [id], onDelete: Cascade)\n\n  @@index([pipelineId])\n}\n\nmodel Product {\n  id          String  @id @default(cuid())\n  companyId   String\n  name        String\n  description String?\n  price       Int     @default(0) // in smallest unit (paise/cents)\n  currency    String  @default(\"INR\")\n  sku         String?\n  isActive    Boolean @default(true)\n\n  @@unique([companyId, sku])\n  @@index([companyId])\n}\n\nmodel Quote {\n  id          String    @id @default(cuid())\n  companyId   String\n  contactId   String?\n  dealId      String?\n  quoteNumber String\n  status      String    @default(\"DRAFT\") // DRAFT, SENT, ACCEPTED, REJECTED, EXPIRED\n  subtotal    Int       @default(0)\n  tax         Int       @default(0)\n  discount    Int       @default(0)\n  total       Int       @default(0)\n  currency    String    @default(\"INR\")\n  validUntil  DateTime?\n  notes       String?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  lineItems QuoteLineItem[]\n\n  @@index([companyId])\n}\n\nmodel QuoteLineItem {\n  id        String  @id @default(cuid())\n  quoteId   String\n  productId String?\n  name      String\n  quantity  Int     @default(1)\n  unitPrice Int     @default(0)\n  total     Int     @default(0)\n\n  quote Quote @relation(fields: [quoteId], references: [id], onDelete: Cascade)\n\n  @@index([quoteId])\n}\n\nmodel Invoice {\n  id            String    @id @default(cuid())\n  companyId     String\n  contactId     String?\n  dealId        String?\n  invoiceNumber String\n  status        String    @default(\"UNPAID\") // UNPAID, PAID, OVERDUE, CANCELLED\n  subtotal      Int       @default(0)\n  tax           Int       @default(0)\n  total         Int       @default(0)\n  currency      String    @default(\"INR\")\n  dueDate       DateTime?\n  paidAt        DateTime?\n  notes         String?\n  createdAt     DateTime  @default(now())\n\n  lineItems InvoiceLineItem[]\n\n  @@index([companyId])\n  @@index([companyId, status])\n}\n\nmodel InvoiceLineItem {\n  id        String @id @default(cuid())\n  invoiceId String\n  name      String\n  quantity  Int    @default(1)\n  unitPrice Int    @default(0)\n  total     Int    @default(0)\n\n  invoice Invoice @relation(fields: [invoiceId], references: [id], onDelete: Cascade)\n\n  @@index([invoiceId])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// PHASE 4: MARKETING\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel Campaign {\n  id             String    @id @default(cuid())\n  companyId      String\n  name           String\n  channel        String    @default(\"whatsapp\") // whatsapp, email, sms\n  status         String    @default(\"DRAFT\") // DRAFT, ACTIVE, PAUSED, COMPLETED\n  segmentId      String?\n  budget         Int?\n  startDate      DateTime?\n  endDate        DateTime?\n  sentCount      Int       @default(0)\n  replyCount     Int       @default(0)\n  convertedCount Int       @default(0)\n  createdAt      DateTime  @default(now())\n  updatedAt      DateTime  @updatedAt\n\n  @@index([companyId])\n  @@index([companyId, status])\n}\n\nmodel Form {\n  id          String   @id @default(cuid())\n  companyId   String\n  name        String\n  fields      Json     @default(\"[]\") // [{name, type, required, label}]\n  isActive    Boolean  @default(true)\n  submitCount Int      @default(0)\n  createdAt   DateTime @default(now())\n\n  submissions FormSubmission[]\n\n  @@unique([companyId, name])\n  @@index([companyId])\n}\n\nmodel FormSubmission {\n  id          String   @id @default(cuid())\n  formId      String\n  companyId   String\n  data        Json     @default(\"{}\")\n  contactId   String?\n  leadId      String?\n  utmSource   String?\n  utmMedium   String?\n  utmCampaign String?\n  ipAddress   String?\n  createdAt   DateTime @default(now())\n\n  form Form @relation(fields: [formId], references: [id], onDelete: Cascade)\n\n  @@index([formId])\n  @@index([companyId])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// PHASE 5: AUTOMATION\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel Workflow {\n  id        String    @id @default(cuid())\n  companyId String\n  name      String\n  isActive  Boolean   @default(false)\n  trigger   Json      @default(\"{}\") // {type: \"contact_created\", conditions: {...}}\n  steps     Json      @default(\"[]\") // [{type: \"action\", action: \"send_message\", config: {...}}]\n  runCount  Int       @default(0)\n  lastRunAt DateTime?\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n\n  executions WorkflowExecution[]\n\n  @@unique([companyId, name])\n  @@index([companyId, isActive])\n}\n\nmodel WorkflowExecution {\n  id          String    @id @default(cuid())\n  workflowId  String\n  companyId   String\n  contactId   String?\n  status      String    @default(\"RUNNING\") // RUNNING, COMPLETED, FAILED\n  steps       Json      @default(\"[]\") // [{step, status, result, timestamp}]\n  error       String?\n  startedAt   DateTime  @default(now())\n  completedAt DateTime?\n\n  workflow Workflow @relation(fields: [workflowId], references: [id], onDelete: Cascade)\n\n  @@index([workflowId])\n  @@index([companyId, status])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// PHASE 7: CUSTOMER SUPPORT\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel Ticket {\n  id              String    @id @default(cuid())\n  companyId       String\n  contactId       String?\n  assignedToId    String?\n  title           String\n  description     String?\n  status          String    @default(\"OPEN\") // OPEN, IN_PROGRESS, WAITING, RESOLVED, CLOSED\n  priority        String    @default(\"MEDIUM\") // LOW, MEDIUM, HIGH, CRITICAL\n  category        String? // bug, feature, billing, general\n  source          String    @default(\"whatsapp\") // whatsapp, email, web, manual\n  firstResponseAt DateTime?\n  resolvedAt      DateTime?\n  closedAt        DateTime?\n  createdAt       DateTime  @default(now())\n  updatedAt       DateTime  @updatedAt\n\n  comments TicketComment[]\n\n  @@index([companyId, status])\n  @@index([companyId, assignedToId])\n  @@index([companyId, priority])\n}\n\nmodel TicketComment {\n  id         String   @id @default(cuid())\n  ticketId   String\n  authorId   String?\n  content    String\n  isInternal Boolean  @default(false) // internal notes not visible to customer\n  createdAt  DateTime @default(now())\n\n  ticket Ticket @relation(fields: [ticketId], references: [id], onDelete: Cascade)\n\n  @@index([ticketId])\n}\n\nmodel KnowledgeBaseArticle {\n  id        String   @id @default(cuid())\n  companyId String\n  title     String\n  content   String\n  category  String?\n  isPublic  Boolean  @default(true)\n  viewCount Int      @default(0)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([companyId])\n  @@index([companyId, category])\n}\n\nmodel SlaPolicy {\n  id                String  @id @default(cuid())\n  companyId         String\n  name              String\n  firstResponseMins Int     @default(60)\n  resolutionMins    Int     @default(480)\n  priority          String  @default(\"MEDIUM\")\n  isActive          Boolean @default(true)\n\n  @@unique([companyId, name])\n  @@index([companyId])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// PHASE 8: REPORTING\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel CustomReport {\n  id        String   @id @default(cuid())\n  companyId String\n  name      String\n  entity    String // contacts, leads, deals, tickets, payments\n  filters   Json     @default(\"{}\")\n  groupBy   String?\n  columns   String[]\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([companyId])\n}\n\nmodel ScheduledReport {\n  id         String    @id @default(cuid())\n  companyId  String\n  reportId   String\n  frequency  String    @default(\"weekly\") // daily, weekly, monthly\n  recipients String[] // email addresses\n  lastSentAt DateTime?\n  nextRunAt  DateTime?\n  isActive   Boolean   @default(true)\n  createdAt  DateTime  @default(now())\n\n  @@index([companyId])\n  @@index([nextRunAt, isActive])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// PHASE 9: INTEGRATIONS\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel Integration {\n  id        String   @id @default(cuid())\n  companyId String\n  type      String // google_calendar, outlook, slack, discord, telegram, instagram\n  config    Json     @default(\"{}\") // encrypted config\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([companyId, type])\n  @@index([companyId])\n}\n\nmodel CalendarEvent {\n  id          String   @id @default(cuid())\n  companyId   String\n  contactId   String?\n  dealId      String?\n  title       String\n  description String?\n  startAt     DateTime\n  endAt       DateTime\n  location    String?\n  externalId  String?\n  createdAt   DateTime @default(now())\n\n  @@index([companyId])\n  @@index([companyId, startAt])\n}\n\nmodel ActivityLog {\n  id         String   @id @default(cuid())\n  companyId  String\n  userId     String?\n  contactId  String?\n  entityType String // contact, lead, deal, ticket, task\n  entityId   String\n  action     String // created, updated, status_changed, assigned, etc.\n  details    Json     @default(\"{}\")\n  createdAt  DateTime @default(now())\n\n  @@index([companyId, createdAt])\n  @@index([companyId, entityType, entityId])\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// PHASE 10: DOCUMENTS & SECURITY\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel Document {\n  id        String   @id @default(cuid())\n  companyId String\n  contactId String?\n  dealId    String?\n  name      String\n  type      String // proposal, contract, invoice_pdf, other\n  fileUrl   String\n  fileSize  Int?\n  mimeType  String?\n  createdAt DateTime @default(now())\n\n  signatures DocumentSignature[]\n\n  @@index([companyId])\n  @@index([companyId, contactId])\n}\n\nmodel DocumentSignature {\n  id          String    @id @default(cuid())\n  documentId  String\n  signerName  String\n  signerEmail String?\n  status      String    @default(\"PENDING\") // PENDING, SIGNED, DECLINED\n  signedAt    DateTime?\n  createdAt   DateTime  @default(now())\n\n  document Document @relation(fields: [documentId], references: [id], onDelete: Cascade)\n\n  @@index([documentId])\n}\n\nmodel ApiKey {\n  id         String    @id @default(cuid())\n  companyId  String\n  name       String\n  keyHash    String    @unique // hashed API key\n  prefix     String // first 8 chars for display\n  scopes     String[] // [\"contacts:read\", \"contacts:write\", etc.]\n  lastUsedAt DateTime?\n  expiresAt  DateTime?\n  isActive   Boolean   @default(true)\n  createdAt  DateTime  @default(now())\n\n  @@index([companyId])\n  @@index([keyHash])\n}\n"
}

